Variant of Joerg's patch

(Submitted by Joerg in a private email)
The old code:

               case '\\': 
                        if (!(flags & FNM_NOESCAPE)) { 
                                pclen = mbrtowc(&pc, pattern, MB_LEN_MAX, 
                                    &patmbs); 
                                if (pclen == (size_t)-1 || pclen == (size_t)-2) 
                                        return (FNM_NOMATCH); 
                                if (pclen == 0) 
                                        pc = '\\'; 
                                pattern += pclen; 
                        } 
                        /* FALLTHROUGH */ 

was wrong and BSD changed this to:

               case '\\': 
                        if (!(flags & FNM_NOESCAPE)) { 
                                pclen = mbrtowc(&pc, pattern, MB_LEN_MAX, 
                                    &patmbs); 
                                if (pclen == (size_t)-1 || pclen == (size_t)-2) 
                                        return (FNM_NOMATCH); 
                                pattern += pclen; 
                        } 
                        /* FALLTHROUGH */ 

but this is incorrect as well.

Correct would be:

               case '\\': 
                        if (!(flags & FNM_NOESCAPE)) { 
                                pclen = mbrtowc(&pc, pattern, MB_LEN_MAX, 
                                    &patmbs); 
                                if (pclen == (size_t)-1 || pclen == (size_t)-2) 
                                        return (FNM_NOMATCH); 
                                if (pclen == 0) 
                                        return (FNM_NOMATCH);
                                pattern += pclen; 
                        } 
                        /* FALLTHROUGH */
